const item = $input.first().json;

// Validation champs obligatoires
if (!item.depart || !item.destination) {
  throw new Error('Champs obligatoires manquants : depart, destination');
}

// Echappement HTML - protege contre injection dans PDF/email
const esc = s => String(s ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/\'/g, '&#x27;');

// Clamp passagers entre 1 et 250 (garde-fou tarif)
const pax = Math.min(Math.max(1, Number(item.passagers) || 30), 250);
const low = 1200 + pax * 14;
const high = Math.round(low * 1.32);
const fmt = (n) => n.toLocaleString('fr-FR');
const date = new Date().toLocaleDateString('fr-FR');

const html = `<!DOCTYPE html>
<html lang="fr">
<head>
<meta charset="UTF-8">
<style>
* { box-sizing: border-box; margin: 0; padding: 0; }
body { font-family: Arial, Helvetica, sans-serif; color: #0E1C2B; padding: 48px; }
.header { display: flex; justify-content: space-between; align-items: flex-start; padding-bottom: 24px; margin-bottom: 32px; border-bottom: 3px solid #C2E812; }
.brand { font-size: 28px; font-weight: 800; }
.brand em { color: #C2E812; font-style: normal; }
.meta { text-align: right; font-size: 12px; color: #666; line-height: 1.8; }
.meta strong { color: #0E1C2B; font-size: 14px; }
h2 { font-size: 11px; text-transform: uppercase; letter-spacing: 1px; color: #888; margin-bottom: 12px; padding-bottom: 6px; border-bottom: 1px solid #eee; }
.section { margin-bottom: 28px; }
.grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 12px 32px; }
.field span { display: block; font-size: 10px; color: #999; text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 2px; }
.field strong { font-size: 13px; font-weight: 600; }
.tarif { background: #0E1C2B; color: white; border-radius: 10px; padding: 28px; text-align: center; }
.tarif-label { font-size: 11px; text-transform: uppercase; letter-spacing: 1px; opacity: 0.6; margin-bottom: 8px; }
.tarif-range { font-size: 32px; font-weight: 800; color: #C2E812; margin-bottom: 6px; }
.tarif-sub { font-size: 13px; opacity: 0.7; }
.tarif-note { font-size: 11px; opacity: 0.45; margin-top: 10px; }
.msg { background: #f8f8f8; border-left: 3px solid #C2E812; padding: 12px 16px; font-size: 13px; line-height: 1.6; color: #444; }
.footer { margin-top: 48px; padding-top: 20px; border-top: 1px solid #eee; font-size: 11px; color: #aaa; text-align: center; line-height: 2; }
</style>
</head>
<body>
<div class="header">
  <div class="brand">Neo<em>travel</em></div>
  <div class="meta">
    <strong>Devis n° ${esc(item.id) || 'NT-' + Date.now()}</strong><br>
    Émis le ${date}<br>
    contact@neotravel.fr · 09 80 40 04 84
  </div>
</div>
<div class="section">
  <h2>Client</h2>
  <div class="grid-2">
    <div class="field"><span>Nom</span><strong>${esc(item.prospect)}</strong></div>
    <div class="field"><span>Email</span><strong>${esc(item.email)}</strong></div>
    <div class="field"><span>Téléphone</span><strong>${esc(item.tel) || '—'}</strong></div>
  </div>
</div>
<div class="section">
  <h2>Trajet</h2>
  <div class="grid-2">
    <div class="field"><span>Départ</span><strong>${esc(item.depart)}</strong></div>
    <div class="field"><span>Destination</span><strong>${esc(item.destination)}</strong></div>
    <div class="field"><span>Date</span><strong>${esc(item.tripDate) || 'À confirmer'}</strong></div>
    <div class="field"><span>Passagers</span><strong>${item.passagers ? esc(item.passagers) + ' personnes' : '—'}</strong></div>
    <div class="field"><span>Véhicule</span><strong>${esc(item.vehicule) || 'À déterminer'}</strong></div>
  </div>
</div>
${item.message ? '<div class="section"><h2>Détails</h2><div class="msg">' + esc(item.message) + '</div></div>' : ''}
<div class="section">
  <h2>Tarif indicatif</h2>
  <div class="tarif">
    <div class="tarif-label">Estimation Neotravel</div>
    <div class="tarif-range">${fmt(low)} € – ${fmt(high)} €</div>
    <div class="tarif-sub">TTC · chauffeur et carburant inclus</div>
    <div class="tarif-note">Tarif indicatif — distance confirmée avant envoi du devis définitif</div>
  </div>
</div>
<div class="footer">
  Neotravel · 09 80 40 04 84 · contact@neotravel.fr<br>
  Ce devis est valable 30 jours à compter du ${date}.
</div>
</body>
</html>`;

const buffer = Buffer.from(html, 'utf-8');
const binaryData = await this.helpers.prepareBinaryData(buffer, 'index.html', 'text/html');

return [{ json: { ...item, tarifMin: low, tarifMax: high }, binary: { indexHtml: binaryData } }];
